internal class KtorGitHubV3RESTAPI(private val client: HttpClient) : GitHubV3RESTAPI {
    override val advisories: Advisories = KtorAdvisories(client)
    override val app: App = KtorApp(client)
    override val appManifests: AppManifests = KtorAppManifests(client)
    override val applications: Applications = KtorApplications(client)
    override val apps: Apps = KtorApps(client)
    override val assignments: Assignments = KtorAssignments(client)
    override val classrooms: Classrooms = KtorClassrooms(client)
    override val codesOfConduct: CodesOfConduct = KtorCodesOfConduct(client)
    override val credentials: Credentials = KtorCredentials(client)
    override val emojis: Emojis = KtorEmojis(client)
    override val enterprises: Enterprises = KtorEnterprises(client)
    override val events: Events = KtorEvents(client)
    override val feeds: Feeds = KtorFeeds(client)
    override val gists: Gists = KtorGists(client)
    override val gitignore: Gitignore = KtorGitignore(client)
    override val installation: Installation = KtorInstallation(client)
    override val issues: Issues = KtorIssues(client)
    override val licenses: Licenses = KtorLicenses(client)
    override val markdown: Markdown = KtorMarkdown(client)
    override val marketplaceListing: MarketplaceListing = KtorMarketplaceListing(client)
    override val meta: Meta = KtorMeta(client)
    override val networks: Networks = KtorNetworks(client)
    override val notifications: Notifications = KtorNotifications(client)
    override val octocat: Octocat = KtorOctocat(client)
    override val organizations: Organizations = KtorOrganizations(client)
    override val orgs: Orgs = KtorOrgs(client)
    override val rateLimit: RateLimit = KtorRateLimit(client)
    override val repos: Repos = KtorRepos(client)
    override val repositories: Repositories = KtorRepositories(client)
    override val search: Search = KtorSearch(client)
    override val teams: Teams = KtorTeams(client)
    override val user: User = KtorUser(client)
    override val users: Users = KtorUsers(client)
    override val versions: Versions = KtorVersions(client)
    override val zen: Zen = KtorZen(client)

    override suspend fun metaRoot(): Root =
        client.get("/").body()
}

fun GitHubV3RESTAPIClient(
    server: GitHubV3RESTAPIServer = GitHubV3RESTAPIServer.Default,
    block: HttpClientConfig<*>.() -> Unit = {},
): GitHubV3RESTAPI {
    val client = HttpClient {
        install(ContentNegotiation) { json() }
        defaultRequest { url(server.url) }
        block()
    }
    return KtorGitHubV3RESTAPI(client)
}
